File : define_usage.c (直接右键另存为下载)Type : c/c++Brief : define usage #include &lt;stdio.h&gt; #include &lt;stdarg.h&gt; /* 宏 : 本质是文本替换，替换的终止条件是：文件中不再含有宏。而当宏参数是另一个宏的 时候，凡宏定义里有用&#39;#&#39;或&#39;##&#39;的地方宏参数是不会再展开， 所以有#或##的宏需 要增加一层转换宏。 # : 将参数转成字符串。 ## : 连接符号，将参数连接在一起。 */ #define TEST hello #define _TO_STR(s) #s // 转换宏 #define TO_STR(s) _TO_STR(s) #define _JOIN(s) #s #define JOIN(a, b) (&quot;String &quot; _JOIN(a##b)) // 字符串可以直接并在一起 // 可变参数 __VA_ARGS__ 需要用 ## 连接，防止可变参数个数为0个 #define LOG(fmt, ...) printf(fmt, ## __VA_ARGS__) /* c/c++中预定义的宏： __FILE__ : 文件名 __FUNCTION__ : 函数名 __LINE__ : 行号 __DATE__ : 日期 __TIME__ : 时间 __STDC__ : 当要求程序严格遵循ANSIC标准时该标识符被赋值为1 __cplusplus : 当用C++编译程序编译时，__cplusplus就会被定义 */ #define debug(fmt, ...) LOG(&quot;DEBUG %s(L%d) &quot; fmt, __FUNCTION__, __LINE__, ## __VA_ARGS__) int main() { // TO_STR(TEST)第一次展开为：_TO_STR(hello)，然后再展开为 #hello， // 之后hello即使是宏也不会再展开，而是用#将参数hello转成了字符串 printf(TO_STR(a&#39;b&#39;c
)); // &quot;a&#39;b&#39;c
&quot; printf(TO_STR(TEST)); // &quot;hello&quot; printf(_TO_STR(a&#39;b&#39;c
)); // &quot;a&#39;b&#39;c
&quot; printf(_TO_STR(TEST)); // &quot;TEST&quot; printf(&quot;
&quot;); printf(JOIN(TEST, abf)); // &quot;String TESTabc&quot; printf(&quot;
&quot;); LOG(&quot;log
&quot;); LOG(&quot;log %d
&quot;, 102); debug(&quot;Error: %d 
&quot;, 1030); printf(&quot;%s
&quot;, __FILE__); printf(&quot;%s
&quot;, __FUNCTION__); printf(&quot;%d
&quot;, __LINE__); printf(&quot;%s
&quot;, __DATE__); printf(&quot;%s
&quot;, __TIME__); printf(&quot;%d
&quot;, __STDC__); return 0; }

File : loan_calculation.py (直接右键另存为下载)Type : pythonBrief : simple calculation of loan #!/usr/bin/python3 ## @file loan_calculation.py # @brief 贷款计算，包括等额本息和等额本金 # # @date 2017-07-21 # @version # @author yehuohan, yehuohan@qq.com, yehuohan@gmail.com # @copyright import sys ## @brief average capital plus interest # 等额本息，每个月还款数额相同，一部分还利息，一部分还本金 # @param A 本金，单位：元 # @param ry 年利率，% # @param time 贷款时间，单位：年 # @return 每月还款 # @retval None def calc_average_ci(A, ry, time_mouth): rate_mouth = ry/12; money_per_mouth = A * (rate_mouth * ((1 + rate_mouth) ** time_mouth)) / ((1+rate_mouth) ** time_mouth - 1) return money_per_mouth ## @brief average capital # 等额本金，每月还的本金一样，这样本金逐渐减少，每月还的利息也会逐渐减少， # 所以每个月还的数额不相同 # @param A 本金，单位：元 # @param ry 年利率，% # @param time 贷款时间，单位：年 # @return 每月还款 # @retval None def calc_average_c(A, ry, time_mouth): rate_mouth = ry/12 A_per_mouth = A / time_mouth money_all_mouth = () k = 0 count_sum = 0 while (k &lt; time_mouth): # 每月还款计算利息时，本金要减去已还的 money_all_mouth += (A_per_mouth + (A - count_sum) * rate_mouth, ) count_sum += A_per_mouth k += 1 return money_all_mouth if __name__ == &quot;__main__&quot;: A = 12000 # 单位：元 rate_year = 11.88 # 单位：% time = 12 # 单位：月 if len(sys.argv) == 1 + 3: A = sys.argv[2] rate_year = sys.argv[3] time = sys.argv[4] m1 = calc_average_ci(A, rate_year/100, time) m2 = calc_average_c(A, rate_year/100, time) print(&quot;
贷款计算&quot;) print(&quot;本金 ：{}元&quot;.format(A)) print(&quot;年利率：{}%&quot;.format(rate_year)) print(&quot;时间 ：{}个月&quot;.format(rate_year)) print(&quot;
等额本息（单位：元）：&quot;) print(&quot;	 每月还款： {}&quot;.format(m1)) print(&quot;	 总利息 ： {}&quot;.format(m1*time - A)) print(&quot;	 本息合计： {}&quot;.format(m1*time)) print(&quot;
